#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Table;

# Function to extract date from the PDF
sub extract_date {
    my ($pdf) = @_;
    my $text = $pdf->textpage->as_text;
    if ($text =~ /\b(\d{1,2} \w{3} \d{4})\b/) {
        return $1;
    }
    return "Date not found";
}

# Function to extract author from the PDF
sub extract_author {
    my ($pdf) = @_;
    my $text = $pdf->textpage->as_text;
    if ($text =~ /\bAuthor:\s+(.*?)\b/) {
        return $1;
    }
    return "Author not found";
}

# Function to extract table information from the PDF
sub extract_table {
    my ($pdf) = @_;
    my $text = $pdf->textpage->as_text;
    if ($text =~ /Table:\s+(.*?)\s+Table/) {
        return $1;
    }
    return "Table not found";
}

# Main script
my $pdf_file = 'example.pdf';

# Open the PDF file
my $pdf = PDF::API2->open($pdf_file);

# Extract data
my $date = extract_date($pdf);
my $author = extract_author($pdf);
my $table = extract_table($pdf);

# Print information
print "Date: $date\n";
print "Author: $author\n";
print "Table: $table\n";

# Cleanup
$pdf->delete;
